#define ROM_MAPPING_COUNT (sizeof(sRomMappings) / sizeof(sRomMappings[0]))

/*
 * Segment ranges for resolving base+offset pointer arithmetic.
 * When code does `FOO_ROM_START + some_offset`, the exact stub lookup fails.
 * This table lets us find the closest segment base and compute the real ROM offset.
 */
typedef struct {
    const void* start_stub;
    u32 rom_start;
    u32 segment_size;
} SegmentRange;

static const SegmentRange sSegmentRanges[] = {
    { ASSET_TABLE_ROM_START,        0x1E40000, 0x9BEE22 },  /* mapfs / asset table */
    { charset_ROM_START,            0x10F1B0,  0x7308 },  /* full charset segment */
    { icon_ROM_START,               0x1CC310,  0x31EA0 },
    { sprites_ROM_START,            0x1943000, 0x23F208 },
    { audio_ROM_START,              0xF00000,  0xA42C40 },
    { msg_ROM_START,                0x1B83000, 0x101D30 },
    { imgfx_data_ROM_START,         0x24B7F0,  0xCA390 },
    { title_bg_1_ROM_START,         0x2191B0,  0x32640 },
    { logos_ROM_START,              0x1FE1B0,  0x1B000 },
    { world_model_anim_kzn_00_ROM_START, 0x3BCC50, 0x2B30 },
    { ui_no_controller_ROM_START,       0x51540,   0x1150 },
    { sprite_shading_profiles_data_ROM_START, 0x315D50, 0xCA0 },
    { sprite_shading_profiles_ROM_START,      0x315B80, 0xE70 },
};

#define SEGMENT_RANGE_COUNT (sizeof(sSegmentRanges) / sizeof(sSegmentRanges[0]))

u32 resolve_rom_offset(const void* addr) {
    /* Exact match first (fast path) */
    for (int i = 0; i < (int)ROM_MAPPING_COUNT; i++) {
        if (sRomMappings[i].addr == addr) return sRomMappings[i].offset;
    }

    /* Fallback 1: Check if the pointer value itself is a valid ROM offset.
     * This handles hardcoded integer addresses like (u8*)0x1B83000 (MSG_ROM_START on US)
     * and cases where the compiler/linker resolved stubs to low addresses. */
    {
        uintptr_t raw = (uintptr_t)addr;
        if (raw > 0 && raw < 0x2800000) {
            return (u32)raw;
        }
    }

    /* Fallback 2: Range-based lookup for base+offset patterns.
     * If addr = SOME_ROM_START + small_offset, find the segment whose start_stub
     * is the LARGEST address <= addr (the containing segment).
     *
     * The old "closest delta" heuristic was wrong: when extern stub symbols are
     * packed close together in BSS/data, an unrelated stub between the base and
     * the target would have a smaller delta and win incorrectly. Instead, we want
     * the segment whose start_stub is nearest to addr from BELOW — the one that
     * actually "owns" this address range in the linker layout. */
    {
        int best_idx = -1;
        const u8* best_start = NULL;
        for (int i = 0; i < (int)SEGMENT_RANGE_COUNT; i++) {
            const u8* stub = (const u8*)sSegmentRanges[i].start_stub;
            ptrdiff_t delta = (const u8*)addr - stub;
            if (delta >= 0 && (u32)delta <= sSegmentRanges[i].segment_size) {
                /* Among all matching segments, pick the one with the highest
                 * start_stub address (nearest from below). */
                if (best_idx < 0 || stub > best_start) {
                    best_idx = i;
                    best_start = stub;
                }
            }
        }
        if (best_idx >= 0) {
            ptrdiff_t delta = (const u8*)addr - best_start;
            return sSegmentRanges[best_idx].rom_start + (u32)delta;
        }
    }

    return 0xFFFFFFFF;
}

#endif
